def reduce_to_range(n):
    while n > 22:
        n = sum(int(d) for d in str(n))
    return n

def calculate_numbers(date_str):
    day, month, year = map(int, date_str.split('.'))
    n1 = reduce_to_range(day)
    n2 = reduce_to_range(month)
    year_sum = sum(int(d) for d in str(year))
    n3 = reduce_to_range(year_sum)
    n4 = reduce_to_range(n1 + n2 + n3)
    n5 = reduce_to_range(n1 + n2 + n3 + n4)
    return [n1, n2, n3, n4, n5]

